pure fn parse_scores(scores: Text) -> List[Text] {
    return split(scores, ",")
}

pure fn extract_name_and_score(entry: Text) -> Tuple[Text, Number] {
    parts = split(entry, ":")
    name = parts[0]
    score = to_number(parts[1])
    return (name, score)
}

pure fn classify_pass_fail(name: Text, score: Number) -> Text {
    if score >= 80 { return join([name, " passed"]) }
    else { return join([name, " failed"]) }
}

entry main(scores: Text) {
    entries = parse_scores(scores)
    results = []
    for entry in entries {
        name, score = extract_name_and_score(entry)
        result = classify_pass_fail(name, score)
        results = append(results, result)
    }
    return join(results, ", ")
}

