import parse_csv from "stdlib/utils"

intent classify_price(text: Text) -> Number {
    goal: extract price as number
}

pure fn is_within_budget(price: Number, budget: Number) -> Boolean {
    return price <= budget
}

entry main(csv_data: Text, budget: Text) {
    parsed_data = parse_csv(csv_data)
    budget_number = to_number(budget)

    recommendations = []
    for item in parsed_data {
        product = item["Product"]
        price_text = item["Price"]
        price = classify_price(price_text)

        if is_within_budget(price, budget_number) {
            recommendations = append(recommendations, product)
        }
    }

    return join(recommendations, ", ")
}
