pure fn is_longer_than(a: Text, b: Text) -> Boolean {
    return length(a) > length(b)
}

pure fn find_longest_word(sentence: Text) -> Text {
    words = split(sentence, " ")
    longest = ""
    for word in words {
        if is_longer_than(word, longest) {
            longest = word
        }
    }
    return longest
}

entry main(x: Text) {
    sentence = "extraordinary programming capabilities"
    longest_word = find_longest_word(sentence)
    explanation = join(["The longest word is "", longest_word, "". It means ", longest_word, " in Latin."], "")
    return explanation
}

