pure fn count_frequencies(s: Text) -> Map {
    freqs = {}
    for c in split(lower(s), "") {
        if has_key(freqs, c) {
            freqs[c] = freqs[c] + 1
        } else {
            freqs[c] = 1
        }
    }
    return freqs
}

pure fn describe_frequencies(freqs: Map) -> Text {
    description = ""
    for key in keys(freqs) {
        description = join([description, to_text(key), ": ", to_text(freqs[key]), " times\n"], "")
    }
    return description
}

entry main(x: Text) {
    text = "hello world"
    frequencies = count_frequencies(text)
    return describe_frequencies(frequencies)
}

