pure fn count_lines(paragraph: Text) -> Number {
    return length(split(paragraph, "\n"))
}

pure fn count_words(paragraph: Text) -> Number {
    return length(split(trim(paragraph), " "))
}

pure fn count_characters(paragraph: Text) -> Number {
    return length(paragraph)
}

intent rate_conciseness(text: Text) -> Text {
    goal: concise_or_verbose
}

entry main(paragraph: Text) {
    lines = count_lines(paragraph)
    words = count_words(paragraph)
    characters = count_characters(paragraph)

    conciseness_rating = rate_conciseness(paragraph)

    return join([
        "Lines: ", to_text(lines), "\n",
        "Words: ", to_text(words), "\n",
        "Characters: ", to_text(characters), "\n",
        "Conciseness: ", conciseness_rating
    ], "")
}

pure fn parse_pairs(input: Text) -> List[Text] {
