pure fn extract_city_lat(pair: Text) -> Tuple[Text, Number] {
    parts = split(pair, ":")
    city = trim(parts[0])
    lat = to_number(trim(parts[1]))
    return (city, lat)
}

pure fn sort_by_latitude(pairs: List[Tuple[Text, Number]]) -> List[Tuple[Text, Number]] {
    sorted_pairs = []
    for pair in pairs {
        sorted_pairs = insert(sorted_pairs, pair, by=pair[1])
    }
    return sorted_pairs
}

intent describe_pattern(cities: List[Tuple[Text, Number]]) -> Text {
    goal: describe the geographic pattern of cities based on their latitudes
}

entry main(input: Text) {
    pairs = parse_pairs(input)
    city_lat_pairs = map(pairs, extract_city_lat)
    sorted_pairs = sort_by_latitude(city_lat_pairs)
    description = describe_pattern(sorted_pairs)
    return description
}

pure fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

entry main(x: Text) {
    results = []
    for i in range(0, 8) {
        results = append(results, to_text(fibonacci(i)))
    }
    return join(results, ", ")
}
